async function fetchAIInsights(sub, campaign, client) {
  const prompt = `You are an expert UGC content analyst for Omnya, a creator agency. Analyze this video submission and return ONLY valid JSON (no markdown, no backticks).

Video Details:
- Platform: ${sub.platform}
- Campaign: ${campaign?.name}
- Client/Brand: ${client?.name}
- Campaign Brief: ${campaign?.description}
- Posted Link: ${sub.posted_link}
- Views 24h: ${sub.views_24h||"not yet tracked"}
- Views 72h: ${sub.views_72h||"not yet tracked"}
- Views 1 Week: ${sub.views_1w||"not yet tracked"}
- Views 1 Month: ${sub.views_1m||"not yet tracked"}
- Likes: ${sub.likes||"not yet tracked"}
- Comments: ${sub.comments||"not yet tracked"}
- Shares: ${sub.shares||"not yet tracked"}
- Saves: ${sub.saves||"not yet tracked"}

Return this exact JSON:
{"score":<0-100>,"scoreLabel":"<label>","summary":"<2-3 sentences>","strengths":["<str1>","<str2>"],"improvements":["<imp1>"],"analyzedAt":"${new Date().toISOString().split("T")[0]}"}`;

  const res = await fetch("https://api.anthropic.com/v1/messages",{
    method:"POST",
    headers:{"Content-Type":"application/json"},
    body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]})
  });
  const data = await res.json();
  const text = data.content?.map(i=>i.text||"").join("")||"";
  return JSON.parse(text.replace(/```json|```/g,"").trim());
}

function AIInsightsPanel({ sub, campaign, client, onUpdate }) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [editingStats, setEditingStats] = useState(false);
  const [saving, setSaving] = useState(false);
  const [stats, setStats] = useState({
    views_24h: sub.views_24h||"", views_72h: sub.views_72h||"",
    views_1w: sub.views_1w||"", views_2w: sub.views_2w||"", views_1m: sub.views_1m||"",
    likes: sub.likes||"", comments: sub.comments||"",
    shares: sub.shares||"", saves: sub.saves||""
  });

  const saveStats = async () => {
    setSaving(true);
    const updates = {};
    Object.entries(stats).forEach(([k,v]) => { updates[k] = v ? Number(v) : null; });
    const { error } = await supabase.from("submissions").update(updates).eq("id", sub.id);
    if (!error) { onUpdate({...sub, ...updates}); setEditingStats(false); }
    else setError("Failed to save stats");
    setSaving(false);
  };

  const analyze = async () => {
    setLoading(true); setError("");
    try {
      const statNums = {};
      Object.entries(stats).forEach(([k,v]) => { statNums[k] = v ? Number(v) : null; });
      const insights = await fetchAIInsights({...sub,...statNums}, campaign, client);
      const { error } = await supabase.from("submissions").update({ai_insights: insights, ...statNums}).eq("id", sub.id);
      if (!error) onUpdate({...sub, ...statNums, ai_insights: insights});
      else setError("Saved locally but DB update failed");
    } catch(e) { setError("AI analysis failed. Please try again."); }
    setLoading(false);
  };

  const ins = sub.ai_insights;

  return (
    <div>
      <div className="card mb-16">
        <div className="flex-between mb-16">
          <div className="card-title" style={{margin:0}}>📊 Video Metrics</div>
          <button className="btn btn-ghost btn-sm" onClick={() => setEditingStats(!editingStats)}>
            {editingStats ? "Cancel" : "✏️ Edit Stats"}
          </button>
        </div>
        {editingStats ? (
          <div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:12}}>
              {[["views_24h","Views 24h"],["views_72h","Views 72h"],["views_1w","Views 1 Week"],["views_2w","Views 2 Weeks"],["views_1m","Views 1 Month"],["likes","Likes"],["comments","Comments"],["shares","Shares"],["saves","Saves"]].map(([k,label]) => (
                <div key={k}>
                  <label className="form-label" style={{fontSize:10}}>{label}</label>
                  <input className="form-input" style={{padding:"8px 10px",fontSize:13}} type="number" placeholder="0" value={stats[k]} onChange={e=>setStats({...stats,[k]:e.target.value})} />
                </div>
              ))}
            </div>
            {error && <div style={{color:"var(--red)",fontSize:12,marginBottom:8}}>{error}</div>}
            <button className="btn btn-primary btn-sm" onClick={saveStats} disabled={saving}>{saving?"Saving...":"Save Stats"}</button>
          </div>
        ) : (
          <div className="metrics-row">
            {[["👁️",sub.views_1w||sub.views_72h||sub.views_24h,"Views"],["❤️",sub.likes,"Likes"],["💬",sub.comments,"Comments"],["🔗",sub.shares,"Shares"],["🔖",sub.saves,"Saves"]].map(([icon,val,label],i) => (
              <div key={i} className="metric-mini">
                <div style={{fontSize:16,marginBottom:4}}>{icon}</div>
                <div className="metric-mini-val" style={{color:val?"var(--ink)":"var(--ink4)"}}>{val?fmtNum(val):"—"}</div>
                <div className="metric-mini-label">{label}</div>
              </div>
            ))}
          </div>
        )}
      </div>
      {ins ? (
        <div className="ai-panel">
          <div className="flex-between mb-16">
            <div className="ai-badge">✨ AI Analysis</div>
            <div style={{fontSize:11,color:"var(--ink3)"}}>Analyzed {fmtDate(ins.analyzedAt)}</div>
          </div>
          <div className="flex-center gap-12 mb-16">
            <div className="ai-score-ring" style={{background:`conic-gradient(${scoreColor(ins.score)} ${ins.score*3.6}deg, var(--bg3) 0deg)`,padding:4}}>
              <div style={{background:"var(--surface)",borderRadius:"50%",width:"100%",height:"100%",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>
                <div className="ai-score-num" style={{color:scoreColor(ins.score)}}>{ins.score}</div>
                <div className="ai-score-sub">score</div>
              </div>
            </div>
            <div>
              <div style={{fontFamily:"Bebas Neue, sans-serif",fontSize:18,marginBottom:4}}>{ins.scoreLabel}</div>
              <div style={{fontSize:12,color:"var(--ink2)",lineHeight:1.6,maxWidth:380}}>{ins.summary}</div>
            </div>
          </div>
          <div className="divider"/>
          <div className="grid-2" style={{gap:16}}>
            <div>
              <div style={{fontSize:11,fontWeight:600,color:"var(--green)",textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:8}}>✓ Strengths</div>
              {ins.strengths.map((s,i) => <div key={i} className="insight-pill insight-strength"><span style={{flexShrink:0}}>✓</span><span>{s}</span></div>)}
            </div>
            <div>
              <div style={{fontSize:11,fontWeight:600,color:"var(--gold)",textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:8}}>↑ Improvements</div>
              {ins.improvements.map((s,i) => <div key={i} className="insight-pill insight-improve"><span style={{flexShrink:0}}>↑</span><span>{s}</span></div>)}
            </div>
          </div>
          <div style={{marginTop:16}}><button className="btn btn-ghost btn-sm" onClick={analyze} disabled={loading}>🔄 Re-analyze</button></div>
        </div>
      ) : (
        <div className="ai-panel">
          {loading ? (
            <div className="ai-loading"><div className="ai-spinner"/><span>AI is analyzing this video...</span></div>
          ) : (
            <div>
              <div className="ai-badge" style={{marginBottom:12}}>✨ AI Performance Analysis</div>
              <p style={{fontSize:13,color:"var(--ink2)",marginBottom:16}}>Get an AI-powered performance score, strengths, and improvement suggestions.</p>
              {error && <div style={{color:"var(--red)",fontSize:12,marginBottom:12}}>{error}</div>}
              <button className="btn btn-primary btn-sm" onClick={analyze}>Run AI Analysis →</button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

