function CreatorDashboard({ user, db }) {
  const creator = db.creators.find(c=>c.user_id===user.id||c.email===user.email);
  if (!creator) return <div className="content"><div className="empty"><div className="empty-icon">👋</div><h3>Profile being set up</h3><p>Your account manager will activate your profile shortly.</p></div></div>;
  
  const mySubs = db.submissions.filter(s=>s.creator_id===creator.id);
  const thisWeek = mySubs.filter(s=>new Date(s.created_at)>new Date(Date.now()-7*86400000)).length;
  const earnings = mySubs.filter(s=>s.final_status==="Approved"&&s.payment_status==="Unpaid").length*(creator.weekly_rate/creator.videos_per_week||10);
  const myJobs = db.campaigns.filter(c=>c.assigned_creators?.includes(creator.id)&&c.status!=="Completed");
  const notifs = [
    ...mySubs.filter(s=>s.concept_status==="Approved").slice(0,2).map(s=>({type:"green",text:<>Concept approved: <strong>{db.campaigns.find(c=>c.id===s.campaign_id)?.name}</strong></>,time:"Recent"})),
    ...mySubs.filter(s=>s.final_status==="Approved").slice(0,2).map(s=>({type:"green",text:<>Final approved: <strong>{db.campaigns.find(c=>c.id===s.campaign_id)?.name}</strong></>,time:"Recent"})),
    ...mySubs.filter(s=>s.concept_status==="Revisions Needed").slice(0,2).map(s=>({type:"orange",text:<>Revisions needed: <strong>{db.campaigns.find(c=>c.id===s.campaign_id)?.name}</strong></>,time:"Recent"})),
  ].slice(0,4);

  return (
    <div className="content">
      <div className="stats-grid">
        <div className="stat-card"><div className="stat-label">Submitted This Week</div><div className="stat-value">{thisWeek}</div></div>
        <div className="stat-card"><div className="stat-label">Total Approved</div><div className="stat-value">{mySubs.filter(s=>s.final_status==="Approved").length}</div></div>
        <div className="stat-card stat-highlight"><div className="stat-label">Approval Rate</div><div className="stat-value">{mySubs.length>0?Math.round((mySubs.filter(s=>s.final_status==="Approved").length/mySubs.length)*100):0}%</div></div>
        <div className="stat-card"><div className="stat-label">Pending Earnings</div><div className="stat-value">{fmtMoney(earnings)}</div></div>
      </div>
      <div className="grid-2">
        <div className="card">
          <div className="card-title">Notifications</div>
          {notifs.length===0&&<div className="empty" style={{padding:24}}><div className="empty-icon">🔔</div><h3>All caught up!</h3></div>}
          {notifs.map((n,i)=>(
            <div key={i} className="notif">
              <div className={`notif-dot notif-dot-${n.type==="orange"?"orange":"green"}`}/>
              <div><div className="notif-text">{n.text}</div><div className="notif-time">{n.time}</div></div>
            </div>
          ))}
        </div>
        <div className="card">
          <div className="card-title">Active Jobs</div>
          {myJobs.length===0&&<div className="empty" style={{padding:24}}><div className="empty-icon">💼</div><h3>No active jobs</h3></div>}
          {myJobs.map(job=>{
            const client=db.clients.find(c=>c.id===job.client_id);
            return (
              <div key={job.id} style={{padding:"12px 0",borderBottom:"1px solid var(--border2)"}}>
                <div className="flex-between mb-8"><div className="fw-600 fs-13">{job.name}</div>{statusBadge(job.status)}</div>
                <div className="flex-center gap-8" style={{fontSize:12,color:"var(--ink3)"}}>
                  <span>{client?.name}</span><span>·</span><span>Due {fmtDate(job.deadline)}</span>
                  <span>·</span><span className="text-green">{fmtMoney(job.pay_per_video)}/video</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

function JobBoard({ user, db, onRefresh }) {
  const creator = db.creators.find(c=>c.user_id===user.id||c.email===user.email);
  const openJobs = db.campaigns.filter(c=>c.status==="Open"&&c.application_type==="Open Application");
  const [applying, setApplying] = useState(null);
  const [loading, setLoading] = useState(false);

  const apply = async (campaignId) => {
    if (!creator) return;
    setLoading(true);
    const camp = db.campaigns.find(c=>c.id===campaignId);
    const updatedCreators = [...(camp.assigned_creators||[]), creator.id];
    await supabase.from("campaigns").update({assigned_creators:updatedCreators,status:"In Progress"}).eq("id",campaignId);
    await onRefresh();
    setApplying(null); setLoading(false);
  };

  if (!creator) return <div className="content"><ErrorMsg msg="Creator profile not found. Contact your account manager." /></div>;

  return (
    <div className="content">
      <div className="mb-16" style={{fontSize:13,color:"var(--ink3)"}}>{openJobs.length} open position{openJobs.length!==1?"s":""} available</div>
      {openJobs.length===0&&<div className="empty"><div className="empty-icon">💼</div><h3>No open jobs right now</h3><p>Check back soon</p></div>}
      {openJobs.map(job=>{
        const client=db.clients.find(c=>c.id===job.client_id);
        const applied=(job.assigned_creators||[]).includes(creator.id);
        return (
          <div key={job.id} className="card mb-16">
            <div className="flex-between mb-8">
              <div>
                <div style={{fontFamily:"Bebas Neue, sans-serif",fontSize:18,marginBottom:4}}>{job.name}</div>
                <div className="flex-center gap-8" style={{fontSize:12}}>
                  <span className="text-muted">{client?.name}</span><span className="text-muted">·</span>
                  <span className="badge badge-blue">{job.format}</span>
                </div>
              </div>
              <div style={{textAlign:"right"}}>
                <div style={{fontFamily:"Bebas Neue, sans-serif",fontSize:22,color:"var(--green)"}}>{fmtMoney(job.pay_per_video)}<span style={{fontSize:12,color:"var(--ink3)",fontFamily:"DM Sans, sans-serif"}}>/video</span></div>
                <div style={{fontSize:11,color:"var(--ink3)"}}>Due {fmtDate(job.deadline)}</div>
              </div>
            </div>
            <div className="divider" style={{margin:"12px 0"}}/>
            <p style={{fontSize:13,color:"var(--ink2)",marginBottom:12}}>{job.description}</p>
            <div className="flex-between">
              <div style={{fontSize:12,color:"var(--ink3)"}}>{job.videos_needed} videos needed</div>
              {applied?<span className="badge badge-green">✓ Applied</span>:<button className="btn btn-primary btn-sm" onClick={()=>setApplying(job)}>Apply Now</button>}
            </div>
          </div>
        );
      })}
      {applying&&(
        <div className="modal-overlay" onClick={()=>setApplying(null)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-title">Apply for {applying.name}</div>
            <div className="modal-sub">{db.clients.find(c=>c.id===applying.client_id)?.name} · {fmtMoney(applying.pay_per_video)}/video</div>
            <p style={{fontSize:13,color:"var(--ink2)",marginBottom:16}}>{applying.description}</p>
            <div className="modal-actions">
              <button className="btn btn-ghost" onClick={()=>setApplying(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={()=>apply(applying.id)} disabled={loading}>{loading?"Applying...":"Confirm Application"}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function SubmitContent({ user, db, onRefresh }) {
  const creator = db.creators.find(c=>c.user_id===user.id||c.email===user.email);
  const myJobs = db.campaigns.filter(c=>(c.assigned_creators||[]).includes(creator?.id)&&c.status!=="Completed");
  const [form, setForm] = useState({campaign_id:myJobs[0]?.id||"",type:"Concept",concept_link:"",posted_link:"",platform:"TikTok"});
  const [submitting, setSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const [err, setErr] = useState("");

  const submit = async () => {
    if (!form.campaign_id||!form.concept_link) { setErr("Please fill in all required fields"); return; }
    setSubmitting(true); setErr("");
    const newSub = {
      creator_id: creator.id, campaign_id: form.campaign_id,
      submission_type: form.type, concept_link: form.concept_link,
      concept_status: "Pending",
      final_status: form.type==="Final"?"Pending":null,
      posted_link: form.posted_link||null, platform: form.platform,
      payment_status: "Unpaid"
    };
    const { error } = await supabase.from("submissions").insert(newSub);
    if (error) { setErr(error.message); setSubmitting(false); return; }
    await onRefresh();
    setSuccess(true); setForm({...form,concept_link:"",posted_link:""});
    setTimeout(()=>setSuccess(false), 4000);
    setSubmitting(false);
  };

  if (!creator) return <div className="content"><ErrorMsg msg="Creator profile not found." /></div>;

  return (
    <div className="content" style={{maxWidth:600}}>
      {success&&<div style={{background:"rgba(26,122,74,0.1)",border:"1px solid var(--green)",borderRadius:"var(--radius)",padding:"14px 20px",marginBottom:20,color:"var(--green)",fontSize:14,fontWeight:600}}>✓ Submitted! Your AM will review it shortly.</div>}
      <div className="card">
        <div className="card-title">New Content Submission</div>
        <div className="form-group">
          <label className="form-label">Campaign</label>
          <select className="select" value={form.campaign_id} onChange={e=>setForm({...form,campaign_id:e.target.value})}>
            {myJobs.length===0&&<option value="">No active jobs — apply to a job first</option>}
            {myJobs.map(j=><option key={j.id} value={j.id}>{j.name}</option>)}
          </select>
        </div>
        <div className="form-group">
          <label className="form-label">Submission Type</label>
          <div style={{display:"flex",gap:8}}>
            {["Concept","Final"].map(t=>(
              <button key={t} className={`btn ${form.type===t?"btn-primary":"btn-ghost"}`} onClick={()=>setForm({...form,type:t})}>
                {t==="Concept"?"📽️":"🎬"} {t} Video
              </button>
            ))}
          </div>
          <div className="form-hint">{form.type==="Concept"?"Submit a screen recording of your concept idea":"Submit the link to your live posted video"}</div>
        </div>
        <div className="form-group">
          <label className="form-label">{form.type==="Concept"?"Concept Video Link (Loom, Drive, etc.)":"Live Posted Video Link"}</label>
          <input className="form-input" placeholder={form.type==="Concept"?"https://loom.com/share/...":"https://tiktok.com/@..."} value={form.concept_link} onChange={e=>setForm({...form,concept_link:e.target.value})} />
        </div>
        {form.type==="Final"&&(
          <div className="form-group">
            <label className="form-label">Platform</label>
            <select className="select" value={form.platform} onChange={e=>setForm({...form,platform:e.target.value})}>
              {["TikTok","Instagram","Facebook","YouTube"].map(p=><option key={p}>{p}</option>)}
            </select>
          </div>
        )}
        {err&&<div style={{color:"var(--red)",fontSize:13,marginBottom:12}}>{err}</div>}
        <button className="btn btn-primary" onClick={submit} disabled={submitting||myJobs.length===0} style={{marginTop:8}}>
          {submitting?"Submitting...":"Submit for Review →"}
        </button>
      </div>
    </div>
  );
}

function MySubmissions({ user, db }) {
  const creator = db.creators.find(c=>c.user_id===user.id||c.email===user.email);
  const mySubs = (creator?db.submissions.filter(s=>s.creator_id===creator.id):[]).sort((a,b)=>new Date(b.created_at)-new Date(a.created_at));
  const [tab, setTab] = useState("All");

  const filtered = mySubs.filter(s=>{
    if(tab==="All") return true;
    if(tab==="Pending") return s.concept_status==="Pending"||s.final_status==="Pending";
    if(tab==="Approved") return s.final_status==="Approved";
    if(tab==="Revisions") return s.concept_status==="Revisions Needed";
    if(tab==="Denied") return s.final_status==="Denied"||s.concept_status==="Denied";
    return true;
  });

  return (
    <div className="content">
      <div className="tabs">
        {["All","Pending","Approved","Revisions","Denied"].map(t=>(
          <div key={t} className={`tab ${tab===t?"active":""}`} onClick={()=>setTab(t)}>{t}</div>
        ))}
      </div>
      {filtered.length===0&&<div className="empty"><div className="empty-icon">📁</div><h3>No submissions found</h3></div>}
      <div className="card">
        <div className="table-wrap">
          <table>
            <thead><tr><th>Campaign</th><th>Type</th><th>Concept</th><th>Final</th><th>Submitted</th><th>Feedback</th></tr></thead>
            <tbody>
              {filtered.map(s=>{
                const camp=db.campaigns.find(c=>c.id===s.campaign_id);
                return (
                  <tr key={s.id}>
                    <td className="fw-600">{camp?.name||"—"}</td>
                    <td>{s.submission_type}</td>
                    <td>{statusBadge(s.concept_status)}</td>
                    <td>{s.final_status?statusBadge(s.final_status):<span className="text-muted">—</span>}</td>
                    <td className="text-muted">{fmtDate(s.created_at)}</td>
                    <td style={{maxWidth:200,fontSize:12,color:"var(--ink3)"}}>{s.feedback||"—"}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function CreatorEarnings({ user, db }) {
  const creator = db.creators.find(c=>c.user_id===user.id||c.email===user.email);
  const myPayments = creator?db.payments.filter(p=>p.creator_id===creator.id):[];
  const totalEarned = myPayments.filter(p=>p.status==="Paid").reduce((a,b)=>a+Number(b.amount_owed),0);
  const totalPending = myPayments.filter(p=>p.status==="Pending").reduce((a,b)=>a+Number(b.amount_owed),0);
  return (
    <div className="content">
      <div className="stats-grid" style={{gridTemplateColumns:"1fr 1fr 1fr"}}>
        <div className="stat-card"><div className="stat-label">Total Earned</div><div className="stat-value">{fmtMoney(totalEarned)}</div></div>
        <div className="stat-card stat-highlight"><div className="stat-label">Pending Payment</div><div className="stat-value">{fmtMoney(totalPending)}</div></div>
        <div className="stat-card"><div className="stat-label">Rate Per Video</div><div className="stat-value">{creator?fmtMoney(creator.weekly_rate/creator.videos_per_week):"—"}</div></div>
      </div>
      <div className="card">
        <div className="card-title">Payment History</div>
        {myPayments.length===0&&<div className="empty" style={{padding:32}}><div className="empty-icon">💰</div><h3>No payments yet</h3></div>}
        <div className="table-wrap">
          <table>
            <thead><tr><th>Week Ending</th><th>Videos</th><th>Amount</th><th>Status</th><th>Paid Date</th></tr></thead>
            <tbody>
              {myPayments.map(p=>(
                <tr key={p.id}>
                  <td>{fmtDate(p.week_ending)}</td><td>{p.videos_approved}</td>
                  <td className="fw-600 text-green">{fmtMoney(p.amount_owed)}</td>
                  <td>{statusBadge(p.status)}</td>
                  <td className="text-muted">{p.paid_date?fmtDate(p.paid_date):"—"}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function CreatorInsights({ user, db, onRefresh }) {
  const creator = db.creators.find(c=>c.user_id===user.id||c.email===user.email);
  const approvedSubs = creator?db.submissions.filter(s=>s.creator_id===creator.id&&s.final_status==="Approved"):[];
  const [selected, setSelected] = useState(approvedSubs[0]?.id||null);

  const updateSub = async (updatedSub) => {
    await onRefresh();
  };

  const sub = db.submissions.find(s=>s.id===selected);
  const campaign = sub?db.campaigns.find(c=>c.id===sub.campaign_id):null;
  const client = campaign?db.clients.find(c=>c.id===campaign.client_id):null;

  return (
    <div className="content">
      {approvedSubs.length===0?<div className="empty"><div className="empty-icon">✨</div><h3>No approved videos yet</h3></div>:(
        <div className="grid-2" style={{alignItems:"start"}}>
          <div>
            <div className="card-title" style={{marginBottom:12}}>Your Approved Videos</div>
            {approvedSubs.map(s=>{
              const camp=db.campaigns.find(c=>c.id===s.campaign_id);
              const ins=s.ai_insights;
              return (
                <div key={s.id} className="card mb-8" style={{cursor:"pointer",border:selected===s.id?"1px solid var(--ink)":"1px solid var(--border)"}} onClick={()=>setSelected(s.id)}>
                  <div className="flex-between">
                    <div><div className="fw-600 fs-13" style={{marginBottom:2}}>{camp?.name}</div><div style={{fontSize:11,color:"var(--ink3)"}}>{s.platform} · Approved {fmtDate(s.approved_date)}</div></div>
                    {ins?<div style={{fontFamily:"Bebas Neue, sans-serif",fontSize:20,color:scoreColor(ins.score)}}>{ins.score}</div>:<span className="badge badge-gray">No score</span>}
                  </div>
                </div>
              );
            })}
          </div>
          <div>{sub&&<AIInsightsPanel sub={sub} campaign={campaign} client={client} onUpdate={updateSub}/>}</div>
        </div>
      )}
    </div>
  );
}

