// ============================================================
// PENDING USERS - OWNER ROLE APPROVAL
// ============================================================
function PendingUsers({ onRefresh }) {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(null);
  const [names, setNames] = useState({});

  const loadPending = async () => {
    setLoading(true);
    const { data } = await supabase.from("user_profiles").select("*").eq("role", "pending");
    setUsers(data || []);
    const n = {};
    (data||[]).forEach(u => { n[u.id] = u.full_name || u.email.split("@")[0]; });
    setNames(n);
    setLoading(false);
  };

  useEffect(() => { loadPending(); }, []);

  const assignRole = async (userId, email, role) => {
    setSaving(userId);
    const displayName = names[userId] || email.split("@")[0];
    await supabase.from("user_profiles").update({ role, full_name: displayName }).eq("id", userId);
    if (role === "am") {
      await supabase.from("account_managers").upsert({ user_id: userId, email, name: displayName }, { onConflict: "user_id" });
    }
    if (role === "creator") {
      await supabase.from("creators").upsert({ user_id: userId, email, name: displayName, status: "Active" }, { onConflict: "user_id" });
    }
    setSaving(null);
    loadPending();
    onRefresh();
  };

  const denyUser = async (userId) => {
    setSaving(userId);
    await supabase.from("user_profiles").update({ role: "denied" }).eq("id", userId);
    setSaving(null);
    loadPending();
  };

  if (loading) return <Spinner />;

  return (
    <div className="content">
      <div className="card mb-16" style={{background:"var(--bg2)"}}>
        <div style={{fontSize:13,color:"var(--ink3)"}}>
          New signups waiting for role assignment. Enter their name, then click Creator or AM to give them access. They'll be able to log in immediately.
        </div>
      </div>
      {users.length === 0 ? (
        <div className="empty"><div className="empty-icon">✅</div><h3>No pending users</h3><p>Everyone has been assigned a role</p></div>
      ) : (
        users.map(u => (
          <div key={u.id} className="card mb-12">
            <div className="flex-between" style={{flexWrap:"wrap",gap:12}}>
              <div style={{flex:1,minWidth:200}}>
                <div style={{fontWeight:600,marginBottom:4}}>{u.email}{u.requested_role&&<span style={{marginLeft:8,fontSize:11,padding:"2px 8px",borderRadius:20,background:u.requested_role==="am"?"var(--blue)":"var(--green)",color:"#fff",fontWeight:500}}>{u.requested_role==="am"?"Account Manager":"Creator"}</span>}</div>
                <input
                  className="form-input"
                  style={{marginTop:6,fontSize:13}}
                  placeholder="Enter their name..."
                  value={names[u.id]||""}
                  onChange={e=>setNames({...names,[u.id]:e.target.value})}
                />
              </div>
              <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                <button className="btn btn-sm" style={{background:"var(--green)",color:"#fff"}} disabled={saving===u.id} onClick={()=>assignRole(u.id, u.email, "creator")}>
                  {saving===u.id?"...":"✓ Creator"}
                </button>
                <button className="btn btn-sm" style={{background:"var(--blue)",color:"#fff"}} disabled={saving===u.id} onClick={()=>assignRole(u.id, u.email, "am")}>
                  {saving===u.id?"...":"✓ AM"}
                </button>
                <button className="btn btn-sm" style={{background:"var(--red)",color:"#fff"}} disabled={saving===u.id} onClick={()=>denyUser(u.id)}>
                  {saving===u.id?"...":"✗ Deny"}
                </button>
              </div>
            </div>
          </div>
        ))
      )}
    </div>
  );
}

